import React, { Suspense } from 'react';
import { Routes, Route, Navigate } from 'react-router-dom';
import { AuthProvider, useAuth } from './context/AuthContext';
import ErrorBoundary from './components/ErrorBoundary';
import { PageLoader } from './components/LoadingSpinner';
import Layout from './components/Layout';

// Pages
import LoginPage         from './pages/LoginPage';
import DashboardPage     from './pages/DashboardPage';
import ContactsPage      from './pages/ContactsPage';
import CampaignsPage     from './pages/CampaignsPage';
import CampaignDetailPage from './pages/CampaignDetailPage';
import TemplatesPage     from './pages/TemplatesPage';
import SendersPage       from './pages/SendersPage';
import AdminPage         from './pages/AdminPage';
import SettingsPage      from './pages/SettingsPage';
import ProfilePage       from './pages/ProfilePage';

// Route guards
const PrivateRoute = ({ children, adminOnly }) => {
  const { user, loading } = useAuth();
  if (loading) return <PageLoader />;
  if (!user)   return <Navigate to="/login" replace />;
  if (adminOnly && user.role !== 'admin') return <Navigate to="/dashboard" replace />;
  return children;
};

function AppRoutes() {
  const { user } = useAuth();
  return (
    <Routes>
      <Route path="/login" element={user ? <Navigate to="/dashboard" /> : <LoginPage />} />
      <Route path="/"      element={<Navigate to="/dashboard" />} />

      <Route element={<PrivateRoute><Layout /></PrivateRoute>}>
        <Route path="/dashboard"        element={<DashboardPage />} />
        <Route path="/contacts"         element={<ContactsPage />} />
        <Route path="/campaigns"        element={<CampaignsPage />} />
        <Route path="/campaigns/:id"    element={<CampaignDetailPage />} />
        <Route path="/templates"        element={<TemplatesPage />} />
        <Route path="/senders"          element={<SendersPage />} />
        <Route path="/settings"         element={<SettingsPage />} />
        <Route path="/profile"          element={<ProfilePage />} />
        <Route path="/admin"            element={
          <PrivateRoute adminOnly>
            <AdminPage />
          </PrivateRoute>
        } />
      </Route>

      {/* 404 */}
      <Route path="*" element={
        <div style={{ minHeight: '100vh', display: 'flex', alignItems: 'center', justifyContent: 'center', flexDirection: 'column', gap: '16px', background: '#f8fafc' }}>
          <div style={{ fontSize: '64px', fontWeight: 800, color: '#e2e8f0' }}>404</div>
          <p style={{ color: '#64748b', fontSize: '16px' }}>Page not found</p>
          <a href="/dashboard" style={{ color: '#6366f1', fontWeight: 600, textDecoration: 'none' }}>← Go to Dashboard</a>
        </div>
      } />
    </Routes>
  );
}

export default function App() {
  return (
    <ErrorBoundary>
      <AuthProvider>
        <AppRoutes />
      </AuthProvider>
    </ErrorBoundary>
  );
}
